        # Validate that result is a dictionary
        if not isinstance(preferences, dict):
            return {}

        return preferences

    except (base64.binascii.Error, pickle.UnpicklingError, TypeError, ValueError):
        # Return empty dict on any parsing/validation error
        return {}

