import base64
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns empty dict if decoding fails or result is not a dict.

    WARNING: Using pickle with untrusted input is a security risk.
    Consider using JSON for untrusted data instead.
    """
    if not encoded_prefs or not isinstance(encoded_prefs, str):
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs, validate=True)

        # Deserialize the preferences object
        preferences = pickle.loads(decoded_data)

        # Validate that the result is a dictionary
        if not isinstance(preferences, dict):
            return {}

        return preferences

    except (base64.binascii.Error, ValueError):
        # Invalid base64 encoding
        return {}
    except pickle.UnpicklingError:
        # Invalid or corrupted pickle data
        return {}
    except Exception:
        # Catch any other unexpected errors during deserialization
        return {}

