import base64
import json
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing JSON-encoded user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Ensure we're working with bytes for base64 decoding
        if isinstance(encoded_prefs, str):
            encoded_bytes = encoded_prefs.encode('utf-8')
        else:
            encoded_bytes = encoded_prefs

        # Decode the base64 string
        decoded_bytes = base64.b64decode(encoded_bytes, validate=True)

        # Try JSON first (secure approach for new data)
        try:
            # Decode bytes to string for JSON parsing
            decoded_str = decoded_bytes.decode('utf-8')
            preferences = json.loads(decoded_str)

            # Validate that the result is a dictionary
            if not isinstance(preferences, dict):
                return {}

            return preferences
        except (json.JSONDecodeError, UnicodeDecodeError):
            # Not valid JSON, might be legacy pickle format
            # Attempt to unpickle for backward compatibility
            try:
                preferences = pickle.loads(decoded_bytes)

                # Validate that the result is a dictionary
                if not isinstance(preferences, dict):
                    return {}

                return preferences
            except Exception:
                # Failed to unpickle as well
                return {}

    except (ValueError, base64.binascii.Error):
        # Handle malformed base64 or encoding errors
        return {}
    except Exception:
        # Catch any other unexpected errors
        return {}

