class RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows safe built-in types.
    This prevents arbitrary code execution from malicious pickle payloads.
    """

    # Whitelist of safe classes that can be unpickled
    SAFE_CLASSES = {
        'builtins.dict',
        'builtins.list',
        'builtins.set',
        'builtins.frozenset',
        'builtins.tuple',
        'builtins.str',
        'builtins.int',
        'builtins.float',
        'builtins.bool',
        'builtins.NoneType',
    }

    def find_class(self, module, name):
        # Only allow safe classes from builtins
        full_name = f"{module}.{name}"
        if full_name in self.SAFE_CLASSES:
            return super().find_class(module, name)
        # Raise an error for any other class
        raise pickle.UnpicklingError(
            f"Attempted to unpickle unauthorized class '{full_name}'. "
            "Only basic data types are allowed."
